-- IMF World Economic Outlook Demo Setup
-- Generated by demo-builder skill
-- Re-runnable: uses CREATE OR REPLACE / IF NOT EXISTS

USE DATABASE API_DEMO;
USE SCHEMA PUBLIC;

-- ============================================================
-- INDICATOR_METADATA: human-readable names for IMF indicator codes
-- ============================================================
CREATE OR REPLACE TABLE INDICATOR_METADATA (
    INDICATOR       VARCHAR(50)     NOT NULL,
    INDICATOR_NAME  VARCHAR(200)    NOT NULL,
    UNIT            VARCHAR(100)    NOT NULL,
    DESCRIPTION     VARCHAR(1000)   NOT NULL
);

