-- ============================================================
-- COUNTRY_METADATA: country names, regions, income groups
-- ============================================================
CREATE OR REPLACE TABLE COUNTRY_METADATA (
    COUNTRY_CODE    VARCHAR(10)     NOT NULL,
    COUNTRY_NAME    VARCHAR(200)    NOT NULL,
    REGION          VARCHAR(100)    NOT NULL,
    INCOME_GROUP    VARCHAR(50)     NOT NULL,
    IS_G7           BOOLEAN         DEFAULT FALSE,
    IS_G20          BOOLEAN         DEFAULT FALSE,
    IS_EMERGING     BOOLEAN         DEFAULT FALSE
);

